insert into public.knowledge_items (type, category, name, description, prompt, tags, stability, use_case, avoid, preview_type)
values
('transition','遮挡类转场','黑影遮挡转场','黑色物体扫过镜头，画面被完全遮住后进入下一幕。','一个黑色阴影从画面前方快速扫过，逐渐遮满整个镜头，画面自然进入黑场，形成顺滑转场；下一镜头从同样的黑暗边缘中显现出来，保持冷色调和紧张氛围。不要文字，不要水印，不要突然多出人物。',array['恐怖','悬疑','黑场','遮挡','AI稳定'],98,'悬疑、恐怖、追逐、人物进入未知空间、场景切换。','不适合明亮轻松的广告片。','shadow'),
('transition','动作类转场','抬手遮挡转场','角色抬手遮住镜头，下一个镜头手放下。','角色缓慢抬起手掌靠近镜头，手掌逐渐遮满整个画面，画面自然变暗，形成顺滑遮挡转场；下一镜头从手掌放下开始，人物仍保持相同情绪和光影。不要文字，不要字幕，不要手指变形。',array['人物','动作','遮挡','回忆','AI稳定'],95,'从现实进入回忆、从对话切到内心独白。','不适合高速动作或多人混乱场景。','hand'),
('shot','景别','特写','放大人物情绪，适合震惊、悲伤、恐惧和思考。','电影感人物特写镜头，人物脸部占据画面主体，眼神中带有紧张和不安，镜头缓慢推进，浅景深，背景虚化，情绪压迫感强。不要字幕，不要文字，不要脸部变形。',array['情绪','冲突','剧情'],89,'情绪爆发、人物反应、悬念揭露。',null,'camera')
